// src/App.js
import React, { useState, useEffect, Suspense, lazy } from "react";
import {
  BrowserRouter as Router,
  Routes,
  Route,
  useLocation,
} from "react-router-dom";
import { AnimatePresence, motion } from "framer-motion";

// Core Components
import Navbar from "./components/Navbar";
import Footer from "./components/Footer";
import SearchBar from "./components/SearchBar";

// Lazy-loaded Pages for performance
const Home = lazy(() => import("./pages/Home"));
const About = lazy(() => import("./pages/About"));
const Domains = lazy(() => import("./pages/Domains"));
const Purpose = lazy(() => import("./pages/Purpose"));
const Team = lazy(() => import("./pages/Team"));
const Vision = lazy(() => import("./pages/Vision"));
const Careers = lazy(() => import("./pages/Careers"));
const Contact = lazy(() => import("./pages/Contact"));
const NotFound = lazy(() => import("./pages/NotFound"));

// -------------------- Scroll to Top on Route Change --------------------
function ScrollToTop() {
  const { pathname } = useLocation();
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: "smooth" });
  }, [pathname]);
  return null;
}

// -------------------- Animated Page Routes --------------------
function AnimatedRoutes() {
  const location = useLocation();

  const pageVariants = {
    initial: { opacity: 0, y: 25 },
    animate: { opacity: 1, y: 0, transition: { duration: 0.5, ease: "easeOut" } },
    exit: { opacity: 0, y: -20, transition: { duration: 0.3, ease: "easeIn" } },
  };

  const routes = [
    { path: "/", element: <Home />, title: "Home - Godemar’s Empire" },
    { path: "/about", element: <About />, title: "About Us - Godemar’s Empire" },
    { path: "/domains", element: <Domains />, title: "Domains - Godemar’s Empire" },
    { path: "/purpose", element: <Purpose />, title: "Our Purpose - Godemar’s Empire" },
    { path: "/team", element: <Team />, title: "Meet the Team - Godemar’s Empire" },
    { path: "/vision", element: <Vision />, title: "Vision - Godemar’s Empire" },
    { path: "/careers", element: <Careers />, title: "Careers - Godemar’s Empire" },
    { path: "/contact", element: <Contact />, title: "Contact - Godemar’s Empire" },
    { path: "*", element: <NotFound />, title: "Page Not Found - Godemar’s Empire" },
  ];

  return (
    <AnimatePresence mode="wait">
      <Routes location={location} key={location.pathname}>
        {routes.map(({ path, element, title }) => (
          <Route
            key={path}
            path={path}
            element={
              <PageWrapper title={title} variants={pageVariants}>
                {element}
              </PageWrapper>
            }
          />
        ))}
      </Routes>
    </AnimatePresence>
  );
}

// -------------------- Page Wrapper (animation + title) --------------------
function PageWrapper({ children, title, variants }) {
  useEffect(() => {
    document.title = title;
  }, [title]);

  return (
    <motion.div
      className="min-h-screen w-full px-4 sm:px-8 md:px-16 bg-black dark:bg-gray-900 text-white"
      variants={variants}
      initial="initial"
      animate="animate"
      exit="exit"
    >
      {children}
    </motion.div>
  );
}

// -------------------- Loading Screen --------------------
function LoadingScreen() {
  return (
    <motion.div
      className="fixed inset-0 flex items-center justify-center bg-black/90 text-white text-lg z-50"
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
    >
      Loading...
    </motion.div>
  );
}

// -------------------- Main App --------------------
function App() {
  const [showSearch, setShowSearch] = useState(false);

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e) => {
      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === "k") {
        e.preventDefault();
        setShowSearch(true);
      } else if (e.key === "/" && !showSearch) {
        e.preventDefault();
        setShowSearch(true);
      } else if (e.key === "Escape") {
        setShowSearch(false);
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [showSearch]);

  return (
    <Router>
      <ScrollToTop />
      <Navbar onSearchClick={() => setShowSearch(true)} />

      {/* Global Search Overlay */}
      <AnimatePresence>
        {showSearch && <SearchBar onClose={() => setShowSearch(false)} />}
      </AnimatePresence>

      {/* Page Content */}
      <main className="pt-16 pb-32 relative z-10">
        <Suspense fallback={<LoadingScreen />}>
          <AnimatedRoutes />
        </Suspense>
      </main>

      {/* Sticky Footer */}
      <Footer />
    </Router>
  );
}

export default App;
